queries.sparql:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type ?description ?price WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasContent ?child ; p:hasStreaming_Service ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  ?child p:description ?description .
  ?child p:price ?price .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Streaming_Services } }
  FILTER(?nf = ?total)
}

